class UnionFind {
    constructor(size) {
        this.parent = Array.from({ length: size }, (_, i) => i);
        this.rank = new Array(size).fill(0);
    }

    find(u) {
        if (this.parent[u] !== u) {
            this.parent[u] = this.find(this.parent[u]);
        }
        return this.parent[u];
    }

    union(u, v) {
        const rootU = this.find(u);
        const rootV = this.find(v);
        if (rootU === rootV) return false;
        if (this.rank[rootU] > this.rank[rootV]) {
            this.parent[rootV] = rootU;
        } else if (this.rank[rootU] < this.rank[rootV]) {
            this.parent[rootU] = rootV;
        } else {
            this.parent[rootV] = rootU;
            this.rank[rootU]++;
        }
        return true;
    }
}

function solve(n, edges, k) {
    const mustEdges = [];
    const optionalEdges = [];
    for (const edge of edges) {
        const [u, v, s, must] = edge;
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    const uf = new UnionFind(n);
    let components = n;

    // Process must edges first
    for (const [u, v, s] of mustEdges) {
        if (uf.union(u, v)) {
            components--;
        }
    }

    if (components === 1) {
        // All nodes are connected by must edges, find min s in must edges
        let minS = Infinity;
        for (const [u, v, s] of mustEdges) {
            minS = Math.min(minS, s);
        }
        return minS;
    }

    // Sort optional edges by descending s
    optionalEdges.sort((a, b) => b[2] - a[2]);

    // Binary search for the maximum possible stability
    let left = 1;
    let right = 1e5;
    let answer = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const tempUF = new UnionFind(n);
        let tempComponents = n;
        let usedK = 0;

        // Union must edges first
        for (const [u, v, s] of mustEdges) {
            if (tempUF.union(u, v)) {
                tempComponents--;
            }
        }

        // Process optional edges with s >= mid or upgraded s >= mid
        for (const [u, v, s] of optionalEdges) {
            if (s >= mid) {
                if (tempUF.union(u, v)) {
                    tempComponents--;
                }
            } else if (s * 2 >= mid && usedK < k) {
                if (tempUF.union(u, v)) {
                    tempComponents--;
                    usedK++;
                }
            }
        }

        if (tempComponents === 1) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}

