import java.util.*

class UnionFind(size: Int) {
    private val parent = IntArray(size) { it }
    private val rank = IntArray(size) { 0 }

    fun find(u: Int): Int {
        if (parent[u] != u) {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    fun union(u: Int, v: Int): Boolean {
        val rootU = find(u)
        val rootV = find(v)
        if (rootU == rootV) return false
        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU
        } else if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV
        } else {
            parent[rootV] = rootU
            rank[rootU]++
        }
        return true
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val mustEdges = mutableListOf<Triple<Int, Int, Long>>()
    val optionalEdges = mutableListOf<Triple<Int, Int, Long>>()
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val s = edge[2]
        val must = edge[3]
